import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.attio.com/rest-api/overview";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Attio API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:attio",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const attioFirewall = {",
    '  name: "attio",',
    '  description: "Attio",',
    "  placeholders: {",
    `    ATTIO_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.attio.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.ATTIO_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Attio firewall config...");
  const ts = generateTypeScript();
  writeOutput("attio", ts, import.meta.dirname);
}
